const url = $input.item.json['YouTube Video URL'];

let videoId = '';
try {
  if (url.includes('watch?v=')) {
    videoId = url.split('watch?v=')[1].split('&')[0];
  } else if (url.includes('youtu.be/')) {
    videoId = url.split('youtu.be/')[1].split('?')[0];
  } else if (url.includes('/shorts/')) {
    videoId = url.split('/shorts/')[1].split('?')[0];
  } else if (url.includes('/embed/')) {
    videoId = url.split('/embed/')[1].split('?')[0];
  }
} catch(e) { videoId = ''; }

return {
  json: {
    videoId: videoId.trim(),
    originalUrl: url,
    userName: $input.item.json['Your Name'],
    summaryStyle: $input.item.json['Summary Style']
  }
};

const data = $input.item.json;

let transcript = '';

// Handle RapidAPI youtube-transcript3 response format
try {
  if (Array.isArray(data)) {
    // Array of transcript segments
    transcript = data.map(item => item.text || item.transcript || '').join(' ');
  } else if (data.transcript && Array.isArray(data.transcript)) {
    transcript = data.transcript.map(item => item.text || '').join(' ');
  } else if (data.transcriptText) {
    transcript = data.transcriptText;
  } else if (typeof data === 'string') {
    transcript = data;
  } else {
    // Try to extract any text content
    transcript = JSON.stringify(data);
  }
} catch(e) {
  transcript = 'Could not parse transcript';
}

// Clean the text
const cleanTranscript = transcript
  .replace(/<[^>]*>/g, ' ')
  .replace(/\[.*?\]/g, '')
  .replace(/\s+/g, ' ')
  .trim()
  .substring(0, 10000);

return {
  json: {
    transcript: cleanTranscript,
    transcriptLength: cleanTranscript.length,
    videoId: $('Extract Video ID').item.json.videoId,
    originalUrl: $('Extract Video ID').item.json.originalUrl,
    userName: $('Extract Video ID').item.json.userName,
    summaryStyle: $('Extract Video ID').item.json.summaryStyle,
    hasTranscript: cleanTranscript.length > 100
  }
};

const summary = $input.item.json.text || 'No summary generated';
const videoUrl = $('Parse Transcript').item.json.originalUrl;
const userName = $('Parse Transcript').item.json.userName;
const style = $('Parse Transcript').item.json.summaryStyle;
